    mapping = json.load(f)['sym_to_name']

names = [mapping.get(s,'') for s in top5]

output = {'top5_symbols': top5, 'company_names': names, 'counts': [res[s] for s in top5]}
print('__RESULT__:')
print(json.dumps(output))"}

