{"code":"import json, os
# Collect var_call_* variables from the provided storage variables
storage_vars = {k: globals()[k] for k in list(globals().keys()) if k.startswith('var_call_')}
res = {}
mapping = None
for name, val in storage_vars.items():
    data = None
    # If val is a string and points to a file, load it
    if isinstance(val, str) and os.path.exists(val):
        try:
            with open(val, 'r') as f:
                data = json.load(f)
        except Exception:
            data = None
    else:
        # val may already be a Python object (list/dict)
        data = val
    if data is None:
        continue
    # If this data contains the sym_to_name mapping
    if isinstance(data, dict) and 'sym_to_name' in data:
        mapping = data['sym_to_name']
    # If it's a list of records from query_db
    if isinstance(data, list):
        for rec in data:
            if isinstance(rec, dict) and 'symbol' in rec:
                symbol = rec.get('symbol')
                cnt = rec.get('cnt')
                # convert to float if possible
                try:
                    cntf = float(cnt)
                except Exception:
                    cntf = None
                res[symbol] = cntf

# If mapping still None, try to find a dict that contains sym_to_name in nested structures
if mapping is None:
    for data in storage_vars.values():
        try:
            if isinstance(data, str) and os.path.exists(data):
                with open(data,'r') as f:
                    d=json.load(f)
            else:
                d=data
            if isinstance(d, dict) and 'sym_to_name' in d:
                mapping = d['sym_to_name']
                break
        except Exception:
            continue

# Prepare sorted results
sorted_syms = sorted([(s,c) for s,c in res.items() if s is not None], key=lambda x: (x[1] if x[1] is not None else -1), reverse=True)
top5 = [s for s,c in sorted_syms[:5]]
counts = [c for s,c in sorted_syms[:5]]

# Map to company names if mapping available
names = []
if mapping:
    for s in top5:
        names.append(mapping.get(s, ''))
else:
    names = [''] * len(top5)

output = {'top5_symbols': top5, 'company_names': names, 'counts': counts}
print('__RESULT__:')
print(json.dumps(output))"}

